#!/usr/bin/env node
/**
 * Build per-product llms-full.txt files from pre-built Markdown twins.
 *
 * For each product listed in PRODUCT_PATHS, this script:
 *   1. Globs `public/<product-path>/**\/index.md` (the per-page Markdown
 *      twins generated by scripts/build-llm-markdown.js).
 *   2. Reads each file, parses its YAML frontmatter for title and url.
 *   3. Sorts by URL path for deterministic output.
 *   4. Concatenates page bodies with `---` separators and per-page
 *      `Source:` lines pointing to canonical HTML URLs.
 *   5. Writes `public/<product-path>/llms-full.txt` with a corpus header.
 *
 * Prerequisites: `npx hugo --quiet && yarn build:md` must have run first.
 *
 * See PLAN.md §3 or AI-visibility-for-InfluxDB.md §5.4 for the design
 * rationale (per-product, not site-wide, to stay within agent context
 * windows). The product list intentionally mirrors the "Full corpora"
 * block in layouts/index.llmstxt.txt and must stay in sync.
 */

import { glob } from 'glob';
import fs from 'fs/promises';
import { readFileSync } from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import yaml from 'js-yaml';
import { getCorpusPaths } from './lib/corpus-paths.js';

/**
 * Resolve --public-dir <path> from argv, defaulting to ./public.
 * Matches the CLI convention used by scripts/build-llm-markdown.js so
 * CircleCI can pass `--public-dir workspace/public` consistently.
 */
function parsePublicDir() {
  const args = process.argv.slice(2);
  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--public-dir' && args[i + 1]) {
      return path.resolve(process.cwd(), args[i + 1]);
    }
  }
  return path.resolve(process.cwd(), 'public');
}

const PUBLIC_ROOT = parsePublicDir();

/**
 * Production fallback used only if sitemap-md.xml lacks a usable origin.
 * In a normal build, the origin is derived from the sitemap (which Hugo
 * generates with the active environment's baseURL — staging vs production
 * vs pr-preview vs local). Hardcoding the production URL as the corpus
 * source would put production URLs into staging artifacts (#7211 review).
 */
const FALLBACK_SITE_URL = 'https://docs.influxdata.com';

/**
 * Load and derive the per-product corpus list from data/products.yml.
 *
 * Single source of truth: this list and the "Full corpora" block in
 * layouts/index.llmstxt.txt both derive from products.yml. The Hugo
 * template applies the same content_path + versions logic via Hugo
 * template functions; scripts/check-md-alternate-coherence.js verifies
 * the two surfaces agree.
 *
 * @returns {Array<{ path: string, name: string }>}
 */
function loadProductPaths() {
  const __filename = fileURLToPath(import.meta.url);
  const __dirname = path.dirname(__filename);
  const productsPath = path.resolve(__dirname, '..', 'data', 'products.yml');
  const products = yaml.load(readFileSync(productsPath, 'utf-8'));
  return getCorpusPaths(products).map(({ path: p, name }) => ({ path: p, name }));
}

const PRODUCT_PATHS = loadProductPaths();

/**
 * Parse a Markdown twin's YAML frontmatter. Returns null if the file lacks
 * frontmatter (in which case the file is skipped — likely a stub or alias).
 *
 * @param {string} content - Raw file content
 * @returns {{ frontmatter: object, body: string } | null}
 */
export function parseFrontmatter(content) {
  if (!content.startsWith('---\n')) return null;
  const end = content.indexOf('\n---\n', 4);
  if (end === -1) return null;
  const yamlBlock = content.slice(4, end);
  const body = content.slice(end + 5);
  try {
    const frontmatter = yaml.load(yamlBlock);
    if (!frontmatter || typeof frontmatter !== 'object') return null;
    return { frontmatter, body };
  } catch {
    return null;
  }
}

/**
 * Read public/sitemap-md.xml and return:
 *   - urls:   Set of eligible page paths (pathname of each <loc>)
 *   - origin: the site origin (https://<host>) extracted from any <loc>.
 *             This reflects the baseURL of whichever Hugo environment built
 *             public/ (production, staging, pr-preview, local). Used as the
 *             source of `Source:` lines and the corpus header URL so staging
 *             artifacts don't carry production URLs.
 *
 * Single source of truth for both "which pages are eligible" and "what
 * origin to use for absolute URLs" — sitemap-md.xml, the head
 * <link rel="alternate"> partial, and this script all agree by construction.
 *
 * @returns {Promise<{ urls: Set<string>, origin: string }>}
 */
export async function loadEligibleUrls(publicRoot = PUBLIC_ROOT) {
  const sitemapPath = path.join(publicRoot, 'sitemap-md.xml');
  const xml = await fs.readFile(sitemapPath, 'utf-8');
  const urls = new Set();
  let origin = null;
  const matches = xml.matchAll(/<loc>([^<]+)<\/loc>/g);
  for (const match of matches) {
    try {
      const url = new URL(match[1]);
      urls.add(url.pathname);
      if (!origin) origin = url.origin;
    } catch {
      /* skip malformed URL */
    }
  }
  return { urls, origin: origin || FALLBACK_SITE_URL };
}

/**
 * Build a single product's corpus.
 *
 * @param {{ path: string, name: string }} product
 * @param {{ urls: Set<string>, origin: string }} eligible - sitemap-md.xml data
 * @returns {Promise<{ product: string, pageCount: number, bytes: number }>}
 */
export async function buildProduct(
  product,
  eligible,
  publicRoot = PUBLIC_ROOT
) {
  const { urls: eligibleUrls, origin } = eligible;
  const productRoot = path.join(publicRoot, product.path);
  const pattern = path.join(productRoot, '**', 'index.md');
  const files = await glob(pattern, { nodir: true });

  const pages = [];
  for (const file of files) {
    const relFile = path.relative(publicRoot, file);
    const urlPath = '/' + relFile;
    if (!eligibleUrls.has(urlPath)) continue;

    const raw = await fs.readFile(file, 'utf-8');
    const parsed = parseFrontmatter(raw);
    if (!parsed) continue;
    if (parsed.frontmatter.type === 'section') continue;

    const pagePath = urlPath.replace(/index\.md$/, '');
    pages.push({
      title: parsed.frontmatter.title || '(untitled)',
      pagePath,
      body: parsed.body.trim(),
    });
  }

  pages.sort((a, b) => a.pagePath.localeCompare(b.pagePath));

  const timestamp = new Date().toISOString();
  const header = [
    `# ${product.name} — full Markdown corpus`,
    '',
    `> Generated ${timestamp} from ${origin}/${product.path}/`,
    `> See ${origin}/llms.txt for the cross-product table of contents.`,
    '',
  ].join('\n');

  const sections = pages.map((p) => {
    return `---\n\n# ${p.title}\n\nSource: ${origin}${p.pagePath}\n\n${p.body}\n`;
  });

  const corpus = header + sections.join('\n');
  const outPath = path.join(productRoot, 'llms-full.txt');
  await fs.writeFile(outPath, corpus, 'utf-8');

  return {
    product: product.name,
    pageCount: pages.length,
    bytes: Buffer.byteLength(corpus, 'utf-8'),
  };
}

async function main() {
  const t0 = Date.now();
  const eligible = await loadEligibleUrls();
  console.log(
    `Loaded ${eligible.urls.size} eligible URLs from sitemap-md.xml (origin: ${eligible.origin})`
  );

  const results = [];
  for (const product of PRODUCT_PATHS) {
    try {
      const result = await buildProduct(product, eligible);
      results.push(result);
    } catch (err) {
      console.error(`Failed to build ${product.path}: ${err.message}`);
      process.exitCode = 1;
    }
  }

  const elapsed = ((Date.now() - t0) / 1000).toFixed(1);
  console.log(
    `\nBuilt ${results.length} per-product llms-full.txt files in ${elapsed}s\n`
  );
  for (const r of results) {
    const sizeMb = (r.bytes / 1024 / 1024).toFixed(2);
    console.log(
      `  ${r.product.padEnd(32)} ${String(r.pageCount).padStart(5)} pages  ${sizeMb} MB`
    );
  }
}

// Only run as CLI when invoked directly (not when imported by tests).
const isMain = import.meta.url === `file://${process.argv[1]}`;
if (isMain) {
  main().catch((err) => {
    console.error(err);
    process.exit(1);
  });
}
